-- Enable RLS without adding permissive testing policies. After running this
-- export and complete_setup.sql, run harden_rls_policies.sql to install the
-- production role/ownership policies.
DO $$
DECLARE t text;
BEGIN
  FOREACH t IN ARRAY ARRAY['users','brands','stores','departments','categories','slas','canned_responses','ticket_rules','pending_users','checklist_configs','audit_templates','audit_assignments','tickets','ticket_comments','ticket_feedback','notifications','audit_submissions']
  LOOP
    EXECUTE format('ALTER TABLE public.%I ENABLE ROW LEVEL SECURITY', t);
    EXECUTE format('DROP POLICY IF EXISTS local_testing_all ON public.%I', t);
  END LOOP;
END $$;

-- Enable realtime for frequently updated tables
DO $$ BEGIN
  ALTER PUBLICATION supabase_realtime ADD TABLE tickets, ticket_comments, notifications;
EXCEPTION WHEN duplicate_object THEN NULL; END $$;

